const input = $('Workflow Input Trigger').first().json;

const BRAND_SPEC = `You are a presentation architect for Backstory. Create structured JSON that will be rendered into branded Google Slides.

SLIDE TYPES (use these type values exactly):

1. "title" — Opening slide. Always first.
   {type:"title", title:"...", subtitle:"..."}

2. "agenda" — Bulleted outline of topics.
   {type:"agenda", title:"Agenda", items:[
     {text:"Topic 1", subitems:["Detail A","Detail B"]},
     {text:"Topic 2"}
   ]}

3. "section_divider" — Section break. Use between major sections.
   {type:"section_divider", title:"Section Name"}

4. "stats" — Three metrics with values, labels, change indicators.
   {type:"stats", title:"Key Metrics", stats:[
     {value:"99.9%", label:"Uptime", change:"+0.2%"},
     {value:"142ms", label:"P95 Latency", change:"-23ms"},
     {value:"2.4M", label:"Daily Requests", change:"+18%"}
   ]}

5. "two_column" — Side-by-side content (wins/challenges, pros/cons).
   {type:"two_column", title:"...",
    left:{header:"Left Title", items:["Item 1","Item 2"]},
    right:{header:"Right Title", items:["Item 1","Item 2"]}}

6. "three_column_cards" — Three colored cards with bullet items.
   {type:"three_column_cards", title:"...", cards:[
     {title:"Card 1", items:["Item A","Item B"]},
     {title:"Card 2", items:["Item A","Item B"]},
     {title:"Card 3", items:["Item A","Item B"]}
   ]}

7. "four_column_timeline" — Quarterly/phase timeline.
   {type:"four_column_timeline", title:"...", quarters:[
     {label:"Q1", focus:"Theme", value:"Initiative", note:"Details"},
     {label:"Q2", focus:"Theme", value:"Initiative", note:"Details"},
     {label:"Q3", focus:"Theme", value:"Initiative", note:"Details"},
     {label:"Q4", focus:"Theme", value:"Initiative", note:"Details"}
   ]}

8. "thank_you" — Closing slide. Always last.
   {type:"thank_you", title:"Thank You"}

GUIDELINES:
- 6-12 slides typical. Always start with title, end with thank_you.
- Use section_divider between major topic areas.
- Use stats when you have 3 quantitative metrics.
- Use two_column for comparisons or contrasts.
- Use three_column_cards for 3 parallel items (teams, priorities).
- Use four_column_timeline for chronological plans.
- Keep text concise — bullet points, not paragraphs.
- Stats values should be short (e.g. "$2.4M", "99.9%", "142ms").

CRITICAL OUTPUT RULES:
- Your FINAL response must be ONLY a valid JSON object. Nothing else.
- No prose before or after. No markdown fences. No explanation.
- Do NOT wrap the JSON in \`\`\`json blocks.
- The JSON must start with { and end with }
- Format: {"title":"Presentation Title","slides":[...]}`;

const RESEARCH_INSTRUCTIONS = `
RESEARCH TOOLS — USE WHEN RELEVANT:
You have access to People.ai MCP tools for account intelligence, sales data, and engagement metrics.

- If the topic involves customers, accounts, deals, or pipeline, use People.ai tools to gather real data.
- Use find_account, get_account_status, ask_sales_ai_about_account to pull engagement data.
- If tools return no results or error, proceed without them — create the best presentation you can from context alone.
- NEVER let a tool failure prevent you from generating the slide JSON.

REMEMBER: After any research, your FINAL output must be ONLY the JSON object. No commentary.`;

const systemPrompt = BRAND_SPEC + RESEARCH_INSTRUCTIONS;
const agentPrompt = input.presentationPrompt || 'Create a general company overview presentation';

return [{ json: {
  systemPrompt,
  agentPrompt,
  channelId: input.channelId,
  assistantName: input.assistantName || 'Your Assistant',
  assistantEmoji: input.assistantEmoji || ':robot_face:',
  presentationPrompt: input.presentationPrompt
}}];

const agentOutput = $('Presentation Agent').first().json;

// Extract text from various possible agent output structures
let text = '';
if (agentOutput.output) {
  text = agentOutput.output;
} else if (agentOutput.text) {
  text = agentOutput.text;
} else if (agentOutput.error) {
  // Agent errored — log it
  console.log('Presentation Agent error:', JSON.stringify(agentOutput.error).substring(0, 500));
  text = '';
} else {
  text = JSON.stringify(agentOutput);
}

let parsed = null;

// Strategy 1: Direct parse (agent returned clean JSON)
try { parsed = JSON.parse(text.trim()); } catch (e) {}

// Strategy 2: Extract from markdown code block
if (!parsed) {
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) try { parsed = JSON.parse(m[1].trim()); } catch (e) {}
}

// Strategy 3: Find the outermost JSON object with slides array
if (!parsed) {
  // Look for {"title":... pattern
  const start = text.indexOf('{"');
  if (start >= 0) {
    // Find matching closing brace by counting braces
    let depth = 0;
    let end = -1;
    for (let i = start; i < text.length; i++) {
      if (text[i] === '{') depth++;
      else if (text[i] === '}') {
        depth--;
        if (depth === 0) { end = i + 1; break; }
      }
    }
    if (end > start) {
      try { parsed = JSON.parse(text.substring(start, end)); } catch (e) {}
    }
  }
}

// Strategy 4: Try extracting any JSON object (greedy regex)
if (!parsed) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) try { parsed = JSON.parse(m[0]); } catch (e) {}
}

// Validate: must have slides array
if (parsed && (!parsed.slides || !Array.isArray(parsed.slides) || parsed.slides.length === 0)) {
  console.log('Parsed JSON but no valid slides array. Keys:', Object.keys(parsed).join(', '));
  parsed = null;
}

// Fallback — create a meaningful single-slide deck from the prompt
if (!parsed) {
  const prompt = $('Resolve Presentation Identity').first().json.presentationPrompt || 'Presentation';
  console.log('WARNING: Could not parse agent output. First 500 chars:', text.substring(0, 500));
  parsed = {
    title: prompt.substring(0, 80),
    slides: [
      {type: "title", title: prompt.substring(0, 80), subtitle: "Content generation needs retry"},
      {type: "two_column", title: "Overview",
        left: {header: "Key Points", items: ["Content generation encountered an issue", "Please retry the presentation command"]},
        right: {header: "Next Steps", items: ["Try again with a more specific prompt", "Check n8n execution logs for details"]}},
      {type: "thank_you", title: "Thank You"}
    ]
  };
}

// Ensure bookend slides
if (parsed.slides[0] && parsed.slides[0].type !== 'title') {
  parsed.slides.unshift({type: 'title', title: parsed.title || 'Presentation', subtitle: ''});
}
if (parsed.slides[parsed.slides.length - 1].type !== 'thank_you') {
  parsed.slides.push({type: 'thank_you', title: 'Thank You'});
}

return [{ json: parsed }];

const slides = $('Parse Slide JSON').first().json.slides;
const presId = $('Create Blank Presentation').first().json.presentationId;
const defaultSlideId = $('Create Blank Presentation').first().json.slides[0].objectId;

const EMU = (inches) => Math.round(inches * 914400);

const RGB = {
  black:       {red:0, green:0, blue:0},
  graphite:    {red:0.090, green:0.090, blue:0.129},
  surfaceGray: {red:0.733, green:0.737, blue:0.737},
  horizon:     {red:0.384, green:0.588, blue:0.678},
  white:       {red:1, green:1, blue:1},
  plum:        {red:0.667, green:0.561, blue:0.627},
  mint:        {red:0.812, green:0.980, blue:0.847},
  ember:       {red:0.816, green:0.286, blue:0.067},
  navy:        {red:0.004, green:0.173, blue:0.282},
  sky:         {red:0.131, green:0.710, blue:1},
  salmon:      {red:0.910, green:0.627, blue:0.565}
};

const IMG = {
  wordmark:   'https://lh3.googleusercontent.com/d/1GMUqmxGqOLoMqsxpiUSduo2hUzE4ei_J',
  booksDark:  'https://lh3.googleusercontent.com/d/1pA1og8eOMnQE4yBT8h9z2oeGneMqCyii',
  booksWhite: 'https://lh3.googleusercontent.com/d/1cL8RmMHzCscyLIdd3Y83RaM_yVXZI6SS',
  gradient:   'https://lh3.googleusercontent.com/d/1edNwnzGIyQPv3v0D0JzpqRllAfmkIIwY'
};

const reqs = [];
const imgReqs = [];
let idC = 0;
const gid = (p) => 'bs_' + p + '_' + (idC++);

reqs.push({deleteObject: {objectId: defaultSlideId}});

function tb(sid, id, x, y, w, h) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'TEXT_BOX',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
}

function ins(id, text) {
  if (!text) return;
  reqs.push({insertText: {objectId: id, text: String(text), insertionIndex: 0}});
}

function sty(id, s) {
  const ts = {};
  const f = [];
  if (s.ff) { ts.fontFamily = s.ff; f.push('fontFamily'); }
  if (s.fs) { ts.fontSize = {magnitude: s.fs, unit: 'PT'}; f.push('fontSize'); }
  if (s.b !== undefined) { ts.bold = s.b; f.push('bold'); }
  if (s.i !== undefined) { ts.italic = s.i; f.push('italic'); }
  if (s.c) { ts.foregroundColor = {opaqueColor: {rgbColor: s.c}}; f.push('foregroundColor'); }
  if (f.length === 0) return;
  reqs.push({updateTextStyle: {objectId: id, style: ts, fields: f.join(','), textRange: {type: 'ALL'}}});
}

function align(id, a) {
  reqs.push({updateParagraphStyle: {objectId: id, style: {alignment: a}, fields: 'alignment', textRange: {type: 'ALL'}}});
}

function rect(sid, id, x, y, w, h, color) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'ROUND_RECTANGLE',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
  reqs.push({updateShapeProperties: {
    objectId: id,
    shapeProperties: {
      shapeBackgroundFill: {solidFill: {color: {rgbColor: color}}},
      outline: {propertyState: 'NOT_RENDERED'}
    },
    fields: 'shapeBackgroundFill,outline'
  }});
}

function colorStripe(sid, y) {
  const cs = [RGB.surfaceGray, RGB.plum, RGB.horizon, RGB.salmon, RGB.surfaceGray];
  cs.forEach((c, i) => {
    const id = gid('cs');
    reqs.push({createShape: {
      objectId: id, shapeType: 'RECTANGLE',
      elementProperties: {
        pageObjectId: sid,
        size: {width: {magnitude: EMU(2), unit: 'EMU'}, height: {magnitude: EMU(0.525), unit: 'EMU'}},
        transform: {scaleX: 1, scaleY: 1, translateX: EMU(i * 2), translateY: EMU(y), unit: 'EMU'}
      }
    }});
    reqs.push({updateShapeProperties: {
      objectId: id,
      shapeProperties: {shapeBackgroundFill: {solidFill: {color: {rgbColor: c}}}, outline: {propertyState: 'NOT_RENDERED'}},
      fields: 'shapeBackgroundFill,outline'
    }});
  });
}

function addWordmark(sid, x, y, w, h) {
  imgReqs.push({createImage: {objectId: gid('wm'), url: IMG.wordmark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

function addBooksDark(sid, x, y) {
  imgReqs.push({createImage: {objectId: gid('bd'), url: IMG.booksDark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(0.7), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

function addNavyStripe(sid) {
  // Simulated gradient: 4 rectangles anchored to right edge, darkest = narrowest
  // API doesn't support gradientFill so we layer solid fills at different opacities
  const steps = [{x:8.2, w:1.8, a:0.18}, {x:8.65, w:1.35, a:0.25},
                 {x:9.1,  w:0.9, a:0.45}, {x:9.55, w:0.45, a:0.85}];
  steps.forEach(s => {
    const id = gid('stripe');
    reqs.push({createShape: {
      objectId: id, shapeType: 'RECTANGLE',
      elementProperties: {
        pageObjectId: sid,
        size: {width: {magnitude: EMU(s.w), unit: 'EMU'}, height: {magnitude: EMU(5.625), unit: 'EMU'}},
        transform: {scaleX: 1, scaleY: 1, translateX: EMU(s.x), translateY: EMU(0), unit: 'EMU'}
      }
    }});
    reqs.push({updateShapeProperties: {
      objectId: id,
      shapeProperties: {
        shapeBackgroundFill: {solidFill: {color: {rgbColor: RGB.graphite}, alpha: s.a}},
        outline: {propertyState: 'NOT_RENDERED'}
      },
      fields: 'shapeBackgroundFill,outline'
    }});
  });
  // White books logo
  imgReqs.push({createImage: {objectId: gid('bw'), url: IMG.booksWhite,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(0.7), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(8.85), translateY: EMU(4.85), unit: 'EMU'}}}});
}

slides.forEach((slide, idx) => {
  const sid = 'slide_' + idx;
  reqs.push({createSlide: {objectId: sid, insertionIndex: idx}});
  reqs.push({updatePageProperties: {objectId: sid,
    pageProperties: {pageBackgroundFill: {solidFill: {color: {rgbColor: RGB.white}}}},
    fields: 'pageBackgroundFill'}});

  switch (slide.type) {
    case 'title': {
      // Taller box (2.2"), smaller font (52pt), subtitle pushed down
      const t = gid('t'); tb(sid, t, 0.5, 0.7, 9, 2.2); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      if (slide.subtitle) {
        const s = gid('t'); tb(sid, s, 0.5, 3.0, 9, 0.65); ins(s, slide.subtitle);
        sty(s, {ff:'Cardo', fs:22, i:true, c:RGB.graphite}); align(s, 'CENTER');
      }
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'agenda': {
      // Title
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Agenda');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});

      // Single text box for all content — one object to click and edit in Slides
      const cid = gid('t');
      tb(sid, cid, 0.6, 1.5, 8.2, 4.0);

      const lines = [];
      const ranges = [];
      let pos = 0;

      (slide.items || []).forEach(item => {
        const text = typeof item === 'string' ? item : item.text;
        const line = '\u25CF  ' + text + '\n';
        ranges.push({start: pos, end: pos + line.length, bold: true, fs: 17, c: RGB.black});
        lines.push(line);
        pos += line.length;
        if (item.subitems) {
          item.subitems.forEach(sub => {
            const sub_line = '    \u2013  ' + sub + '\n';
            ranges.push({start: pos, end: pos + sub_line.length, bold: false, fs: 14, c: RGB.graphite});
            lines.push(sub_line);
            pos += sub_line.length;
          });
        }
      });

      reqs.push({insertText: {objectId: cid, text: lines.join(''), insertionIndex: 0}});

      ranges.forEach(r => {
        reqs.push({updateTextStyle: {
          objectId: cid,
          style: {
            fontFamily: 'Roboto',
            fontSize: {magnitude: r.fs, unit: 'PT'},
            bold: r.bold,
            foregroundColor: {opaqueColor: {rgbColor: r.c}}
          },
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: r.start, endIndex: r.end}
        }});
      });

      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'section_divider': {
      // Taller box for long section names
      const t = gid('t'); tb(sid, t, 0.5, 1.4, 9, 2.0); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'stats': {
      // Title
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Key Metrics');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});

      // One text box per stat — value + label + change as a single editable block
      const pos = [0.4, 3.5, 6.6];
      (slide.stats || []).slice(0,3).forEach((st, i) => {
        const cid = gid('t');
        tb(sid, cid, pos[i], 1.6, 3.0, 3.5);

        const vLine = (st.value || '') + '\n';
        const lLine = (st.label || '') + '\n';
        const cLine = st.change || '';
        const full = vLine + lLine + cLine;

        reqs.push({insertText: {objectId: cid, text: full, insertionIndex: 0}});

        // Value — large, bold, navy
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Cardo', fontSize: {magnitude: 28, unit: 'PT'}, bold: true,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.navy}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: 0, endIndex: vLine.length}}});

        // Label — medium, graphite
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Roboto', fontSize: {magnitude: 15, unit: 'PT'}, bold: false,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.graphite}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: vLine.length, endIndex: vLine.length + lLine.length}}});

        // Change — small, horizon blue
        if (st.change) {
          reqs.push({updateTextStyle: {objectId: cid,
            style: {fontFamily: 'Roboto', fontSize: {magnitude: 14, unit: 'PT'}, bold: true,
                    foregroundColor: {opaqueColor: {rgbColor: RGB.horizon}}},
            fields: 'fontFamily,fontSize,bold,foregroundColor',
            textRange: {type: 'FIXED_RANGE', startIndex: vLine.length + lLine.length, endIndex: full.length}}});
        }

        // Center-align everything
        reqs.push({updateParagraphStyle: {objectId: cid,
          style: {alignment: 'CENTER'}, fields: 'alignment',
          textRange: {type: 'ALL'}}});
      });

      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'two_column': {
      // Title box 1.1" tall at 34pt; headers and content shifted down
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      [{d:slide.left, x:0.5, clr:RGB.horizon}, {d:slide.right, x:5.2, clr:RGB.ember}].forEach(col => {
        if (!col.d) return;
        const h = gid('t'); tb(sid, h, col.x, 1.5, 4.2, 0.55); ins(h, col.d.header || '');
        sty(h, {ff:'Roboto', fs:22, b:true, c:col.clr});
        const items = (col.d.items || []).map(it => '\u2022 ' + it).join('\n');
        const b = gid('t'); tb(sid, b, col.x, 2.1, 4.2, 3.1); ins(b, items);
        sty(b, {ff:'Roboto', fs:16, c:RGB.graphite});
      });
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
    case 'three_column_cards': {
      // Slide title — full width
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});

      // 3 cards centered across full 10" slide: w=2.6, gap=0.4, left margin=0.7
      const cx = [0.7, 3.7, 6.7]; const cc = [RGB.horizon, RGB.plum, RGB.ember];
      (slide.cards || []).slice(0,3).forEach((card, i) => {
        // Heading above card in dark text
        const ct = gid('t'); tb(sid, ct, cx[i], 1.45, 2.6, 0.45); ins(ct, card.title || '');
        sty(ct, {ff:'Roboto', fs:15, b:true, c:RGB.black});

        // Colored card
        rect(sid, gid('r'), cx[i], 1.92, 2.6, 3.35, cc[i]);

        // Single text box for all bullets
        const items = (card.items || []).map(it => '\u2022 ' + it).join('\n');
        const ci = gid('t'); tb(sid, ci, cx[i]+0.15, 2.05, 2.3, 3.1); ins(ci, items);
        sty(ci, {ff:'Roboto', fs:13, c:RGB.white});
      });

      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'four_column_timeline': {
      // Slide title — full width
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});

      // 4 columns centered across full 10" slide: w=2.0, gap=0.2, left margin=0.6
      const qx = [0.6, 2.8, 5.0, 7.2]; const qc = [RGB.horizon, RGB.plum, RGB.ember, RGB.navy];
      (slide.quarters || []).slice(0,4).forEach((q, i) => {
        // Stage label above card
        const ql = gid('t'); tb(sid, ql, qx[i], 1.45, 2.0, 0.45); ins(ql, q.label || '');
        sty(ql, {ff:'Roboto', fs:15, b:true, c:RGB.black}); align(ql, 'CENTER');

        // Colored card
        rect(sid, gid('r'), qx[i], 1.95, 2.0, 2.9, qc[i]);

        // Focus Area label
        const fl = gid('t'); tb(sid, fl, qx[i], 2.1, 2.0, 0.32); ins(fl, 'Focus Area');
        sty(fl, {ff:'Roboto', fs:10, c:RGB.white}); align(fl, 'CENTER');

        // Main value — single text box per card
        const fv = gid('t'); tb(sid, fv, qx[i], 2.45, 2.0, 0.85); ins(fv, q.focus || q.value || '');
        sty(fv, {ff:'Cardo', fs:16, b:true, c:RGB.white}); align(fv, 'CENTER');

        if (q.note) {
          const n = gid('t'); tb(sid, n, qx[i], 3.95, 2.0, 0.4); ins(n, q.note);
          sty(n, {ff:'Roboto', fs:11, c:RGB.white}); align(n, 'CENTER');
        }
      });

      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'thank_you': {
      const t = gid('t'); tb(sid, t, 0.5, 1.8, 9, 1.5);
      ins(t, (slide.title || 'THANK YOU').toUpperCase());
      sty(t, {ff:'Cardo', fs:72, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.5, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    default: {
